        (9, 'Brick retaining wall', 'Sturdy brick retaining wall constructed (8m long x 1.2m high) to level sloping backyard. Proper concrete footing, weep holes for drainage, and reinforcement bars through the wall. Professional bricklaying with perfect mortar lines.', 'Heritage Brickwork', 4800, 7200),
        (9, 'Brick fence construction', 'New brick fence built along front boundary (12 meters). Double brick construction with decorative capping, built on concrete footing. Matches house brickwork perfectly and provides excellent privacy and security.', 'Boundary Brick Specialists', 6500, 9500),
        (9, 'Repair damaged brickwork', 'Repaired damaged brickwork on exterior wall. Old bricks removed and replaced with matching bricks, mortar joints raked out and repointed. Wall looks as good as new now.', 'Brick Repair Pros', 1200, 2500),
        (9, 'Build new brick BBQ', 'Custom brick BBQ built in backyard entertaining area. Double skin construction with concrete footing, fire bricks for cooking area, and decorative brick finish. BBQ is a fantastic addition to our outdoor space.', 'Outdoor Living Brickwork', 3500, 6000),
        (9, 'Construct brick garden bed', 'Raised garden bed constructed with bricks (3m long x 1m wide x 0.5m high). Proper concrete footing and drainage holes included. Great for growing vegetables and flowers in the backyard.', 'Garden Bed Bricklayers', 1500, 3000),
        (9, 'Brick veneer repair', 'Repaired damaged brick veneer on exterior wall. Old bricks removed and replaced with matching bricks, mortar joints raked out and repointed. Wall looks as good as new now.', 'Brick Repair Pros', 1200, 2500),
        
        -- Category 10: Waterproofing
        (10, 'Bathroom waterproofing', 'Complete bathroom waterproofing prior to tiling. Membrane applied to floor and 150mm up walls, floor waste sealed properly, all penetrations sealed. Flood tested for 24 hours - passed perfectly. Comes with 10 year warranty.', 'AquaShield Waterproofing', 1200, 1800),
        (10, 'Balcony waterproofing', 'Balcony waterproofing with membrane system. Old tiles removed, substrate repaired, waterproof membrane applied with proper detailing to drainage and upstands. Flood tested and certified before new tiles installed.', 'Balcony Seal Experts', 2500, 4000),
        (10, 'Roof waterproofing', 'Roof waterproofing treatment for flat roof area. High-quality liquid applied membrane that creates a seamless waterproof layer. Roof cleaned and prepared properly before application. Excellent protection against leaks and weather damage.', 'Roof Seal Solutions', 3000, 5000),
        (10, 'Basement waterproofing', 'Basement waterproofing system installed to prevent water ingress. Exterior excavation, waterproof membrane applied to walls and floor, drainage system installed to divert water away from foundation. Professional job that has kept the basement dry even during heavy rains.', 'Basement Waterproofing Pros', 8000, 15000),
        
